const PRODUCT_CATALOG_URL="products.json?v=20260722-webp";function apiBase(){return String(window.COMELEAPI_API_BASE||"").trim().replace(/\/+$/,"")}function apiUrl(t){const r=apiBase();return r?`${r}${t}`:t}async function fetchProducts(t,r={}){const o=await fetch(t,{headers:{Accept:"application/json"},...r});if(!o.ok)throw new Error(`risposta non valida (${o.status})`);const a=await o.json(),n=Array.isArray(a)?a:a.products;if(!Array.isArray(n))throw new Error("formato prodotti non valido");return n}async function loadCatalog(){return fetchProducts(PRODUCT_CATALOG_URL,{credentials:"same-origin"})}async function loadProducts(){try{return await fetchProducts(apiUrl("/api/products"),{credentials:apiBase()?"omit":"same-origin"})}catch(t){try{return await loadCatalog()}catch(r){return console.error("[data] catalogo prodotti non disponibile.",{apiError:t,catalogError:r}),[]}}}function saveProducts(t){console.warn("[data] saveProducts non disponibile nel sito pubblico.",t)}async function resetProducts(){return clone(await loadCatalog())}async function getVisibleProducts(){return(await loadProducts()).filter(t=>!1!==t.visible).sort((t,r)=>(t.order??0)-(r.order??0))}function makeId(){return"p-"+Date.now().toString(36)+"-"+Math.random().toString(36).slice(2,7)}function clone(t){return JSON.parse(JSON.stringify(t))}window.SaraData={loadProducts:loadProducts,saveProducts:saveProducts,resetProducts:resetProducts,getVisibleProducts:getVisibleProducts,makeId:makeId};